#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-03-24

# Validate frontmatter schema for agents and skills
# Catches missing required fields BEFORE CI
#
# Exit codes:
#   0 - All valid
#   1 - Validation failures found

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/.." && pwd)"
AGENTS_DIR="$PROJECT_ROOT/src/agents"
SKILLS_DIR="$PROJECT_ROOT/src/skills"

RED='\033[0;31m'
GREEN='\033[0;32m'
NC='\033[0m'

ERRORS=0

# Extract a frontmatter field using the project parser
get_field() {
  local file="$1"
  local field="$2"
  node -e "
    const { parseYamlFrontmatter } = require('$PROJECT_ROOT/scripts/lib/parse-frontmatter.js');
    const fs = require('fs');
    const content = fs.readFileSync('$file', 'utf-8');
    const result = parseYamlFrontmatter(content);
    const val = result.frontmatter['$field'];
    if (val === undefined || val === null || val === '') process.exit(1);
    console.log(typeof val === 'string' ? val : JSON.stringify(val));
  " 2>/dev/null
}

# ===== Agent Validation =====
AGENT_REQUIRED_FIELDS="name description category context model"

for agent_file in "$AGENTS_DIR"/*.md; do
  [[ ! -f "$agent_file" ]] && continue
  agent_name=$(basename "$agent_file" .md)

  for field in $AGENT_REQUIRED_FIELDS; do
    if ! get_field "$agent_file" "$field" >/dev/null 2>&1; then
      echo -e "  ${RED}✗${NC} Agent '$agent_name': missing required field '$field'"
      ERRORS=$((ERRORS + 1))
    fi
  done

  # Check description length (≤250 bytes)
  desc=$(get_field "$agent_file" "description" 2>/dev/null || echo "")
  desc_len=${#desc}
  if [[ "$desc_len" -gt 250 ]]; then
    echo -e "  ${RED}✗${NC} Agent '$agent_name': description $desc_len bytes > 250 limit"
    ERRORS=$((ERRORS + 1))
  fi
done

# ===== Skill Validation =====
SKILL_REQUIRED_FIELDS="name description tags version author user-invocable complexity"

for skill_dir in "$SKILLS_DIR"/*/; do
  skill_file="$skill_dir/SKILL.md"
  [[ ! -f "$skill_file" ]] && continue
  skill_name=$(basename "$skill_dir")

  for field in $SKILL_REQUIRED_FIELDS; do
    if ! get_field "$skill_file" "$field" >/dev/null 2>&1; then
      echo -e "  ${RED}✗${NC} Skill '$skill_name': missing required field '$field'"
      ERRORS=$((ERRORS + 1))
    fi
  done

  # Verify name matches directory
  declared_name=$(get_field "$skill_file" "name" 2>/dev/null || echo "")
  if [[ -n "$declared_name" ]] && [[ "$declared_name" != "$skill_name" ]]; then
    echo -e "  ${RED}✗${NC} Skill '$skill_name': name '$declared_name' doesn't match directory"
    ERRORS=$((ERRORS + 1))
  fi
done

if [[ "$ERRORS" -gt 0 ]]; then
  echo ""
  echo -e "${RED}Frontmatter validation FAILED: $ERRORS error(s)${NC}"
  exit 1
fi

echo -e "  ${GREEN}✓${NC} All agents and skills have valid frontmatter"
exit 0
